// Pattern 2: composite literal mcpContent{Type:"text"}.
func pattern2(payload string) server.mcpToolResult {
	return server.mcpToolResult{
		Content: []server.mcpContent{ // want `evidencelint: mcpContent.*Type.*text`
			{Type: "text", Text: payload},
		},
	}
